from pathlib import Path
from typing import Optional

ROOT = Path.cwd()
TMP = ROOT / '.jan-rerank-turboquant-scoring-full-tmp'
BASE_SCRIPT_B64 = ''
FILES_B64 = '{\n  "src-tauri/plugins/tauri-plugin-llamacpp/src/gguf/scoring.rs": "",\n  "src-tauri/plugins/tauri-plugin-llamacpp/permissions/autogenerated/commands/score_hub_model.toml": "",\n  "web-app/src/components/ui/badge.tsx": "",\n  "web-app/src/lib/modelQuantization.ts": "",\n  "web-app/src/utils/scoreUtils.ts": "",\n  "web-app/src/hooks/useModelScores.ts": "",\n  "web-app/src/components/ModelScoreBadge.tsx": ""\n}'


def fail(message: str) -> None:
    raise SystemExit(message)


def read_rel(rel: str) -> str:
    return (ROOT / rel).read_text(encoding='utf-8')


def write_rel(rel: str, data: str) -> None:
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(data, encoding='utf-8')


def require_rel(rel: str) -> None:
    if not (ROOT / rel).exists():
        fail('Missing required file: ' + rel + '. Run from the Jan repository root after resetting to upstream/main.')


def replace_once(rel: str, old: str, new: str, label: str, marker: Optional[str] = None) -> None:
    s = read_rel(rel)
    if (marker and marker in s) or new.strip()[:100] in s:
        return
    if old not in s:
        fail('Could not find target for ' + label + ' in ' + rel)
    write_rel(rel, s.replace(old, new, 1))


def insert_after(rel: str, needle: str, insertion: str, label: str, marker: Optional[str] = None) -> None:
    s = read_rel(rel)
    if (marker and marker in s) or insertion.strip()[:100] in s:
        return
    idx = s.find(needle)
    if idx < 0:
        fail('Could not find insertion point for ' + label + ' in ' + rel)
    idx += len(needle)
    write_rel(rel, s[:idx] + insertion + s[idx:])


def insert_before(rel: str, needle: str, insertion: str, label: str, marker: Optional[str] = None) -> None:
    s = read_rel(rel)
    if (marker and marker in s) or insertion.strip()[:100] in s:
        return
    idx = s.find(needle)
    if idx < 0:
        fail('Could not find insertion point for ' + label + ' in ' + rel)
    write_rel(rel, s[:idx] + insertion + s[idx:])


def replace_regex(rel: str, pattern: str, repl: str, label: str, flags=re.S) -> None:
    s = read_rel(rel)
    if repl.strip()[:100] in s:
        return
    new, n = re.subn(pattern, lambda _m: repl, s, count=1, flags=flags)
    if n == 0:
        fail('Could not find regex target for ' + label + ' in ' + rel)
    write_rel(rel, new)


def load_json_rel(rel: str):
    return json.loads(read_rel(rel))


def dump_json_rel(rel: str, data) -> None:
    write_rel(rel, json.dumps(data, indent=2, ensure_ascii=False) + '\n')


def run_base_applicator() -> None:
    if TMP.exists():
        shutil.rmtree(TMP)
    TMP.mkdir(parents=True, exist_ok=True)
    base_path = TMP / 'apply-base-features.py'
    base_path.write_text(base64.b64decode(BASE_SCRIPT_B64).decode('utf-8'), encoding='utf-8')
    print(f'>>> running {base_path.relative_to(ROOT)}')
    old = sys.argv[:]
    try:
        sys.argv = [str(base_path)]
        runpy.run_path(str(base_path), run_name='__main__')
    finally:
        sys.argv = old


def write_scoring_files() -> None:
    for rel, encoded in json.loads(FILES_B64).items():
        write_rel(rel, base64.b64decode(encoded).decode('utf-8'))


