def apply_full_scoring_system() -> None:
    print('>>> applying full PR #8115 scoring system')
    write_scoring_files()
    patch_rust_scoring()
    patch_guest_and_extension_scoring()
    patch_frontend_scoring_types_and_service()
    patch_hub_scoring_ui()
    print('Full llmfit hub scoring system applied.')


def main() -> None:
    run_base_applicator()
    apply_full_scoring_system()
    print('All Jan rerank/turboquant/features plus full scoring applied. Run pnpm typecheck and cargo check now; the compiler enjoys making humans beg.')


if __name__ == '__main__':
    main()
